contracts/AutoRefund.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "./Campaign.sol";

contract AutoRefund {
    Campaign public campaignContract;

    event RefundIssued(uint indexed campaignId, address indexed contributor, uint amount, uint timestamp);
    event RefundIssuedToAll(uint indexed campaignId, uint count, uint totalAmount);

    constructor(address _campaignContract) {
        campaignContract = Campaign(_campaignContract);
    }

    // Extracted issueRefundToAll
    function issueRefundToAll(uint _id) public {
        (
            , , , , uint goal, uint deadline, uint fundsRaised, bool isWithdrawn, bool isRefunded, 
        ) = campaignContract.campaigns(_id);

        require(block.timestamp >= deadline, "Campaign still active");
        require(!isWithdrawn, "Funds were withdrawn");
        require(fundsRaised < goal, "Goal met: no refunds");
        require(!isRefunded, "Campaign already refunded macro");

        uint poolSize = campaignContract.getContributorCount(_id);
        uint aggregatedPayouts = 0;
        uint successfulDisbursements = 0;

        for (uint i = 0; i < poolSize; i++) {
            (address targetBacker, uint targetValue) = campaignContract.getContributor(_id, i);
            bool alreadyRefunded = campaignContract.refunded(_id, targetBacker);

            if (targetValue > 0 && !alreadyRefunded) {
                bool success = campaignContract.executeAuthorizedRefund(_id, targetBacker, targetValue);
                if (success) {
                    aggregatedPayouts += targetValue;
                    successfulDisbursements++;
                    emit RefundIssued(_id, targetBacker, targetValue, block.timestamp);
                }
            }
        }

        if (successfulDisbursements > 0) {
            campaignContract.markCampaignRefunded(_id);
            emit RefundIssuedToAll(_id, successfulDisbursements, aggregatedPayouts);
        }
    }

    // Extracted refund (pull-based)
    function refund(uint _id) public {
        (
            , , , , uint goal, uint deadline, uint fundsRaised, , , 
        ) = campaignContract.campaigns(_id);

        require(block.timestamp >= deadline, "Campaign still active");
        require(fundsRaised < goal, "Goal met: no refunds");

        (, uint contributedAmount) = campaignContract.getContributorByAddress(_id, msg.sender);
        require(contributedAmount > 0, "No contribution found");
        require(!campaignContract.refunded(_id, msg.sender), "Already refunded");

        bool success = campaignContract.executeAuthorizedRefund(_id, msg.sender, contributedAmount);
        require(success, "Refund failed");

        emit RefundIssued(_id, msg.sender, contributedAmount, block.timestamp);
    }
}

contracts/Campaign.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "./UserAuth.sol";
import "./RewardToken.sol";

contract Campaign {
    struct CampaignData {
        uint id;
        address creator;
        string title;
        string description;
        uint goal;
        uint deadline;
        uint fundsRaised;
        bool isWithdrawn;
        bool isRefunded;
        uint createdAt;
    }

    uint public campaignCount;
    mapping(uint => CampaignData) public campaigns;

    event CampaignCreated(
        uint indexed id,
        address indexed creator,
        string title,
        uint goal,
        uint deadline,
        uint timestamp
    );

    event ContributionMade(
        uint indexed campaignId,
        address indexed contributor,
        uint amount,
        uint timestamp
    );

    event RefundIssued(
        uint indexed campaignId,
        address indexed contributor,
        uint amount,
        uint timestamp
    );

    event RefundCompleted(uint indexed campaignId, uint timestamp);
    event RefundIssuedToAll(uint indexed campaignId, uint count, uint totalAmount);

    event FundsWithdrawn(
        uint indexed campaignId,
        address indexed creator,
        uint amount,
        uint timestamp
    );

    RewardToken public rewardToken;
    address public autoRefundContract;

    constructor(address _rewardTokenAddress) {
        rewardToken = RewardToken(_rewardTokenAddress);
    }

    function setAutoRefundContract(address _address) external {
        require(autoRefundContract == address(0), "Already set");
        autoRefundContract = _address;
    }

    mapping(uint => mapping(address => uint)) public contributions;
    mapping(uint => address[]) public campaignContributors;
    mapping(uint => mapping(address => bool)) public refunded;

    function createCampaign(
        string memory _title,
        string memory _description,
        uint _goal,
        uint _deadline
    ) public {
        require(_goal > 0, "Goal must be greater than 0");
        require(_deadline > block.timestamp, "Deadline must be in the future");
        campaignCount++;
        campaigns[campaignCount] = CampaignData({
            id: campaignCount,
            creator: msg.sender,
            title: _title,
            description: _description,
            goal: _goal,
            deadline: _deadline,
            fundsRaised: 0,
            isWithdrawn: false,
            isRefunded: false,
            createdAt: block.timestamp
        });
        emit CampaignCreated(
            campaignCount,
            msg.sender,
            _title,
            _goal,
            _deadline,
            block.timestamp
        );
    }

    function getActiveCampaigns() public view returns (CampaignData[] memory) {
        uint activeCount = 0;
        for (uint i = 1; i <= campaignCount; i++) {
            if (
                block.timestamp < campaigns[i].deadline &&
                !campaigns[i].isWithdrawn
            ) {
                activeCount++;
            }
        }
        CampaignData[] memory activeCampaigns = new CampaignData[](activeCount);
        uint index = 0;
        for (uint i = 1; i <= campaignCount; i++) {
            if (
                block.timestamp < campaigns[i].deadline &&
                !campaigns[i].isWithdrawn
            ) {
                activeCampaigns[index] = campaigns[i];
                index++;
            }
        }
        return activeCampaigns;
    }

    function getMyCampaigns(
        address _creator
    ) public view returns (CampaignData[] memory) {
        uint count = 0;
        for (uint i = 1; i <= campaignCount; i++) {
            if (campaigns[i].creator == _creator) {
                count++;
            }
        }
        CampaignData[] memory myCampaigns = new CampaignData[](count);
        uint index = 0;
        for (uint i = 1; i <= campaignCount; i++) {
            if (campaigns[i].creator == _creator) {
                myCampaigns[index] = campaigns[i];
                index++;
            }
        }
        return myCampaigns;
    }

    function contribute(uint _id) public payable {
        CampaignData storage c = campaigns[_id];
        require(block.timestamp < c.deadline, "Campaign has ended");
        require(!c.isWithdrawn, "Funds already withdrawn");
        require(!c.isRefunded, "Campaign refunded");
        require(msg.value > 0, "Contribution must be greater than 0");
        require(c.fundsRaised < c.goal, "Goal already reached");
        require(msg.sender != c.creator, "Creator cannot contribute");

        if (contributions[_id][msg.sender] == 0) {
            campaignContributors[_id].push(msg.sender);
        }

        c.fundsRaised += msg.value;
        contributions[_id][msg.sender] += msg.value;

        emit ContributionMade(_id, msg.sender, msg.value, block.timestamp);
    }

    // Authorized Refund Execution Methods (Called by AutoRefund.sol)
    function executeAuthorizedRefund(uint _id, address _contributor, uint _amount) external returns (bool) {
        require(msg.sender == autoRefundContract, "Unauthorized: Only AutoRefund contract");
        require(!refunded[_id][_contributor], "Already refunded");
        
        refunded[_id][_contributor] = true;
        (bool success, ) = payable(_contributor).call{value: _amount}("");
        if (!success) {
            refunded[_id][_contributor] = false; // Revert state on failure
        }
        return success;
    }

    function markCampaignRefunded(uint _id) external {
        require(msg.sender == autoRefundContract, "Unauthorized: Only AutoRefund contract");
        campaigns[_id].isRefunded = true;
    }

    function getContributorByAddress(uint _id, address _contributor) external view returns (address, uint) {
        return (_contributor, contributions[_id][_contributor]);
    }

    function withdraw(uint _id) public {
        CampaignData storage c = campaigns[_id];
        require(msg.sender == c.creator, "Only creator can withdraw");
        require(!c.isWithdrawn, "Already withdrawn");
        require(!c.isRefunded, "Campaign refunded");
        require(c.fundsRaised >= c.goal, "Goal not met");

        c.isWithdrawn = true;
        (bool sent, ) = payable(c.creator).call{value: c.fundsRaised}("");
        require(sent, "Withdraw failed");
        emit FundsWithdrawn(_id, msg.sender, c.fundsRaised, block.timestamp);

        // Mint reward tokens to contributors
        for (uint i = 0; i < campaignContributors[_id].length; i++) {
            address contributor = campaignContributors[_id][i];
            uint amount = contributions[_id][contributor];
            if (amount > 0) {
                // Example: 1 token per 1 wei contributed
                rewardToken.mint(contributor, amount);
            }
        }
    }

    function getContributors(uint _id) public view returns (address[] memory) {
        return campaignContributors[_id];
    }

    function getContributorCount(uint _id) public view returns (uint) {
        return campaignContributors[_id].length;
    }

    function getContributor(uint _id, uint _index) public view returns (address contributor, uint amount) {
        address cInfo = campaignContributors[_id][_index];
        return (cInfo, contributions[_id][cInfo]);
    }
}

contracts/RewardToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// Import OpenZeppelin ERC20 implementation
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract RewardToken is ERC20, Ownable {
    constructor(address initialOwner) ERC20("CampaignRewardToken", "CRT") Ownable(initialOwner) {}

    function mint(address to, uint amount) external onlyOwner {
        _mint(to, amount);
    }
}

contracts/UserAuth.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract UserAuth {
    struct User {
        string username;
        address userAddress;
        bool isRegistered;
    }

    mapping(address => User) private users;
    mapping(string => address) private usernameToAddress;

    event UserRegistered(address indexed userAddress, string username);

    function register(string memory _username) public {
        require(!users[msg.sender].isRegistered, "Already registered");
        require(bytes(_username).length > 0, "Username cannot be empty");
        require(usernameToAddress[_username] == address(0), "Username already taken");

        users[msg.sender] = User({
            username: _username,
            userAddress: msg.sender,
            isRegistered: true
        });

        usernameToAddress[_username] = msg.sender;

        emit UserRegistered(msg.sender, _username);
    }

    function isUserRegistered(address _user) public view returns (bool) {
        return users[_user].isRegistered;
    }

    function isUsernameRegistered(string memory _username) public view returns (bool) {
        return usernameToAddress[_username] != address(0);
    }

    function getUser(address _user) public view returns (string memory, address, bool) {
        User memory u = users[_user];
        return (u.username, u.userAddress, u.isRegistered);
    }

    function deleteAccount() public {
        require(users[msg.sender].isRegistered, "Not registered");

        string memory username = users[msg.sender].username;

        delete usernameToAddress[username];
        delete users[msg.sender];
    }
}

